z = .3/uv1.y;
rs0.x = uv1.x*z;
rs0.y = z;
rs.x = rs0.x + uTime/2;
rs.y = rs0.y + uTime;

noise = lum(texture(sampler_noise_hq,rs/2));
noise = noise-.55;
float mask = clamp01(12*(uv1.y));

uv2 = uv1+.5;
//uv2 *= uAspect.yx;

uv3 =fract(uv2-noise*.1*mask );
vec2 hor = vec2 (uTexSize.z,0);
vec2 ver = vec2 (0, uTexSize.w);
float dx = lum(GetPixel(uv3+hor) - GetPixel(uv3-hor));
float dy = lum(GetPixel(uv3+ver) - GetPixel(uv3-ver));
vec2 dz = vec2 (dx,dy);
//dz *= (length(dz) >= .01);
uv3 += dz * (1-mask);

//Strahl
uv4 = vec2(.5,uv1.x/uv1.y);
uv4 = fract(.06*audioLowSmooth*uv4);
vec3 col = 1;
vec3 ret3 = GetPixel(uv4*14);
ret3 += (.008/(length(uv1)))*col;
//ret2 *= q10;

vec3 mus = .02 / (length(uv1+.45+dz*16));
float mus2 = clamp01(.01*abs(uv3.x-.5)/abs(uv3.y-.55)-dz*4);


float stars = clamp01(1/((vUv.x*3234224*vUv.y)%22345));

ret1 = GetPixel(fract(uv3));
ret1 *= 1-mask/2;;

float fmask = clamp01(1-lum(ret1*4));
ret2 = ret1  + mus * (1-mask) * 2  ;
